  function norm(v){ return String(v == null ? '' : v).replace(/\s+/g, ' ').trim().toLowerCase(); }
  function cleanText(v){ return String(v == null ? '' : v).replace(/\s+/g, ' ').trim(); }
  function uniqBy(list, keyFn){
    var seen = new Set();
    return (list || []).filter(function(item){
      var key = keyFn(item);
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }
  function shuffle(arr){
    var out = (arr || []).slice();
    for (var i = out.length - 1; i > 0; i -= 1) {
      var j = Math.floor(Math.random() * (i + 1));
      var tmp = out[i];
      out[i] = out[j];
      out[j] = tmp;
    }
    return out;
  }
  function pick(arr){ return (arr && arr.length) ? arr[Math.floor(Math.random() * arr.length)] : null; }
  function ensureArray(v){ return Array.isArray(v) ? v : (v ? [v] : []); }
  function findGradeSubject(ids){
    if (typeof SUBJ === 'undefined' || !Array.isArray(SUBJ)) return null;
    var list = ensureArray(ids);
    for (var i = 0; i < list.length; i += 1) {
      var subj = SUBJ.find(function(item){ return item && item.id === list[i]; });
      if (subj) return subj;
    }
    return null;
  }
